parameters.prompt:
WORKFLOW_VERSION: {{node_search_brief.workflow_version}}

Du bist ein Lead-Discovery-Agent für Dee Empire. Diese Workflow-Datei ist ein TEMPLATE: Die Kampagne kommt nur aus dem editierbaren Prompt-Node.

CAMPAIGN PROMPT / AUFGABE:
{{node_search_brief.campaign_prompt}}

NUTZE GOOGLE_SEARCH:
{{node_search_brief.searches_text}}

BEREITS IN DER DATENBANK / UNBEDINGT AUSSCHLIESSEN:
{{node_search_brief.excluded_domains_text}}

REGELN:
- Wenn CAMPAIGN PROMPT leer ist, gib exakt {"leads":[]} zurück.
- Erstelle aus dem CAMPAIGN PROMPT konkrete Google-Suchen: Ort(e), Branche(n), Zieltyp, Ausschlüsse, gewünschte Signale.
- Gib KEINE URL zurück, deren Domain in der Ausschlussliste steht.
- Gib KEINE großen Plattformen/Marktplätze/Verzeichnisse zurück, außer der Prompt verlangt ausdrücklich Verzeichnisquellen.
- Bevorzuge echte Firmenwebsites, Kontaktseiten, Impressum, Telefon, Öffnungszeiten, Termin- oder Angebotsseiten.
- Wenn ein Suchergebnis Portal/Verzeichnis ist, suche tiefer und wähle echte Unternehmen.
- Sammle maximal {{node_search_brief.max_leads_per_run}} eindeutige Leads.
- lead_type soll kurz und stabil sein, aus dem Prompt abgeleitet, z.B. "arztpraxis", "handwerk", "restaurant", "local", "salon".

OUTPUT — NUR VALIDES JSON — KEIN MARKDOWN — kein Text davor/danach:
{"leads":[
  {"url":"https://firma.de/kontakt","company_name":"Firma Name","lead_type":"local","city":"Stadt","phone":"N/A","website_status":"website_found","appointment_status":"unknown","reason":"warum dieser Lead passt"}
]}

parameters.script:
module.exports = async function({ input, services }) {
  const rawMaxSearches = Number(input && input.max_searches_per_run);
  const rawMaxLeads = Number(input && input.max_leads_per_run);
  const MAX_SEARCHES_PER_RUN = Number.isFinite(rawMaxSearches) && rawMaxSearches > 0 ? Math.min(rawMaxSearches, 20) : 6;
  const MAX_LEADS_PER_RUN = Number.isFinite(rawMaxLeads) && rawMaxLeads > 0 ? Math.min(rawMaxLeads, 100) : 18;
  const WORKFLOW_VERSION = 'data_scraping_prompt_template_v1';
  const campaignPrompt = String((input && input.campaign_prompt) || '').trim();

  const normalizeDomain = (url) => {
    try { return new URL(String(url)).hostname.replace(/^www\./, '').toLowerCase(); }
    catch (e) { return null; }
  };

  const existing = await services.db({
    query: 'SELECT website_url FROM leads WHERE website_url IS NOT NULL ORDER BY created_at DESC LIMIT 1000',
    parameters: [],
    limit: 1000
  });
  if (existing.status !== 'completed') throw new Error(existing.error || 'Could not load existing lead domains');

  const excludedDomains = [...new Set((existing.rows || []).map(r => normalizeDomain(r.website_url)).filter(Boolean))];
  const runStartedAt = new Date().toISOString();

  return {
    workflow_version: WORKFLOW_VERSION,
    campaign_prompt: campaignPrompt,
    campaign_focus: campaignPrompt || 'EMPTY TEMPLATE PROMPT - edit node_campaign_prompt.campaign_prompt before running.',
    searches_text: campaignPrompt
      ? `Create up to ${MAX_SEARCHES_PER_RUN} google_search queries from this campaign prompt:\n${campaignPrompt}`
      : 'NO CAMPAIGN PROMPT PROVIDED. Do not invent a campaign; return {"leads":[]}.',
    excluded_domains: excludedDomains.slice(0, 300),
    excluded_domains_text: excludedDomains.slice(0, 300).join(', '),
    existing_domain_count: excludedDomains.length,
    run_started_at: runStartedAt,
    max_searches_per_run: MAX_SEARCHES_PER_RUN,
    max_leads_per_run: MAX_LEADS_PER_RUN
  };
};

module.exports = async function({ input }) {
  let parsed = {};
  if (input && input.output && typeof input.output === 'object' && !Array.isArray(input.output)) {
    parsed = input.output;
  } else {
    let raw = (input && (input.text || input.result)) || '{}';
    if (typeof raw !== 'string') raw = JSON.stringify(raw);
    raw = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
    try { parsed = JSON.parse(raw); } catch (e) { parsed = {}; }
  }
  if (!parsed || typeof parsed !== 'object') parsed = {};

  const escapeSql = (str) => {
    if (!str) return 'N/A';
    return String(str).replace(/'/g, "''");
  };

  return {
    company_name: escapeSql(parsed.company_name || 'Unknown'),
    website_url: escapeSql(parsed.website_url),
    phone: escapeSql(parsed.phone),
    email: escapeSql(parsed.email),
    icebreaker: escapeSql(parsed.icebreaker)
  };
};

module.exports = async function({ input, services }) {
  const MAX_LEADS_PER_RUN = 25;
  const BLOCKED_DOMAINS = [
    'barmer.de', 'aok.de', 'bed-ev.de', 'jameda.de', 'doctolib.de', 'treatwell.de',
    'planity.com', 'facebook.com', 'instagram.com', 'linkedin.com', 'google.com',
    'quelle-oder-firmenwebsite.de', 'firma-beispiel.de', 'example.com',
    'kurier.de', 'kvb.de', 'hwk-oberfranken.de', 'deutsches-jagdportal.de', 'wittich.de',
    'mein-amadeus.de', 'utopolis-coburg.com', 'vsbamberg.de', 'adticket.de', 'hs-coburg.de',
    'bamberg-news.com', 'vhs-bamberg-land.de', 'ebensfeld.de'
  ];
  const clean = (s) => {
    if (s === undefined || s === null) return null;
    const v = String(s).replace(/'/g, "''").trim();
    return (v === 'N/A' || v === 'None' || v === '') ? null : v;
  };
  const sqlEscape = (s) => String(s).replace(/'/g, "''");
  const domainOf = (url) => {
    try { return new URL(String(url)).hostname.replace(/^www\./, '').toLowerCase(); }
    catch (e) { return ''; }
  };
  const BUSINESS_RE = /(praxis|tierarzt|kleintier|zahnarzt|physio|ergo|logo|podolog|kfz|auto|werkstatt|elektr|sanitär|heizung|maler|friseur|kosmetik|fußpflege|fahrschule)/i;
  const BAD_LEAD_RE = /(beispiel|example|zeitung|kurier|nachrichten|news|bereitschaftsdienst|verwaltung|bürgerbüro|handwerkskammer|kammer|jagdportal|pdf|wittich|programm|veranstaltung|ticket|hochschule|universität|vhs|markt |gemeinde|behörde|portal|plattform|keine spezifische|allgemeine .*suche|empfehlungsplattform|krankenhaus|klinikum|senioren|größere|kette|standortliste|keine .*praxis|keine .*firma)/i;
  const isBlockedDomain = (url) => {
    const domain = domainOf(url);
    return BLOCKED_DOMAINS.some(d => domain === d || domain.endsWith('.' + d));
  };
  const isBadLeadText = (lead) => BAD_LEAD_RE.test(`${lead.company_name || ''} ${lead.reason || ''} ${lead.url || ''}`);
  const parseLeadObjects = (raw) => {
    if (typeof raw !== 'string') return [];
    const s = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
    if (!s.includes('leads') && !s.includes('company_name')) return [];
    try {
      const parsed = JSON.parse(s);
      return parsed && Array.isArray(parsed.leads) ? parsed.leads : [];
    } catch (e) {}

    // Salvage complete lead objects from truncated model output. This keeps the run useful
    // when the agent produces valid objects but the final JSON array is cut off.
    const leads = [];
    const objectRe = /\{[^{}]*"url"\s*:\s*"[^"]+"[^{}]*\}/g;
    const matches = s.match(objectRe) || [];
    for (const m of matches) {
      try {
        const obj = JSON.parse(m.replace(/,\s*\}/g, '}'));
        if (obj && obj.url) leads.push(obj);
      } catch (e) {}
    }
    return leads;
  };
  const inferLeadType = (query, title) => {
    const text = `${query || ''} ${title || ''}`.toLowerCase();
    if (/tierarzt|kleintier|tierklinik/.test(text)) return 'tierarzt';
    if (/arzt|zahnarzt|physio|ergo|logo|podolog/.test(text)) return 'arztpraxis';
    if (/kfz|auto|elektr|sanitär|heizung|maler|werkstatt/.test(text)) return 'handwerk';
    return 'local';
  };
  const collectSearchResultLeads = (obj, seen = new Set()) => {
    const leads = [];
    if (!obj || typeof obj !== 'object' || seen.has(obj)) return leads;
    seen.add(obj);
    if (Array.isArray(obj)) {
      for (const item of obj) leads.push(...collectSearchResultLeads(item, seen));
      return leads;
    }
    if (obj.role === 'tool' && obj.name === 'google_search' && typeof obj.content === 'string') {
      try {
        const data = JSON.parse(obj.content);
        const query = data.query || '';
        for (const r of (data.results || [])) {
          const url = clean(r.url);
          const title = clean(r.title) || 'Unknown';
          const text = `${title} ${r.snippet || ''} ${url || ''}`;
          if (url && url.startsWith('http') && !isBlockedDomain(url) && BUSINESS_RE.test(text) && !BAD_LEAD_RE.test(text)) {
            leads.push({
              url,
              company_name: title,
              lead_type: inferLeadType(query, title),
              phone: 'N/A',
              city: 'N/A',
              website_status: 'website_found',
              appointment_status: 'unknown',
              reason: 'from google_search fallback'
            });
          }
        }
      } catch (e) {}
    }
    for (const value of Object.values(obj)) leads.push(...collectSearchResultLeads(value, seen));
    return leads;
  };
  const collectBodies = (obj, seen = new Set()) => {
    const bodies = [];
    if (!obj || typeof obj !== 'object' || seen.has(obj)) return bodies;
    seen.add(obj);
    if (Array.isArray(obj)) {
      for (const item of obj) bodies.push(...collectBodies(item, seen));
      return bodies;
    }
    if (Array.isArray(obj.items)) for (const it of obj.items) bodies.push((it && it.body) ? it.body : it);
    if (Array.isArray(obj.leads)) bodies.push(obj);
    if (obj.output && typeof obj.output === 'object') {
      if (Array.isArray(obj.output.leads)) bodies.push(obj.output);
      bodies.push(...collectBodies(obj.output, seen));
    }
    for (const key of ['result', 'text', 'content']) {
      const leads = parseLeadObjects(obj[key]);
      if (leads.length) bodies.push({ leads });
    }
    for (const value of Object.values(obj)) bodies.push(...collectBodies(value, seen));
    return bodies;
  };

  let leads = [];
  for (const body of collectBodies(input)) {
    for (const r of (body.leads || [])) {
      if (!r || typeof r !== 'object' || isBadLeadText(r)) continue;
      const url = clean(r.url || r.website_url);
      if (url && url.startsWith('http') && !isBlockedDomain(url)) leads.push({
        url,
        company_name: clean(r.company_name) || 'Unknown',
        lead_type: clean(r.lead_type) || 'unknown',
        phone: clean(r.phone) || 'N/A',
        city: clean(r.city) || clean(r.town) || 'N/A',
        website_status: clean(r.website_status) || 'unknown',
        appointment_status: clean(r.appointment_status) || 'unknown',
        reason: clean(r.reason) || 'N/A'
      });
    }
  }

  if (leads.length === 0) {
    leads = collectSearchResultLeads(input);
  }

  const seenUrls = new Set();
  leads = leads.filter(l => {
    const k = l.url.toLowerCase().replace(/\/$/, '');
    if (seenUrls.has(k)) return false;
    seenUrls.add(k);
    return true;
  });

  if (leads.length === 0) return { items: [], total_found: 0, total_new: 0, total_skipped: 0, total_queued: 0, max_leads_per_run: MAX_LEADS_PER_RUN };

  const urlList = leads.map(l => `'${sqlEscape(l.url)}'`).join(',');
  const phones = leads.map(l => l.phone).filter(p => p && p !== 'N/A').map(p => `'${sqlEscape(p)}'`);
  const names = leads.map(l => l.company_name).filter(n => n && !['N/A','None','Unknown'].includes(n)).map(n => `LOWER('${sqlEscape(n)}')`);
  const clauses = [`website_url IN (${urlList})`];
  if (phones.length) clauses.push(`phone IN (${phones.join(',')})`);
  if (names.length) clauses.push(`LOWER(company_name) IN (${names.join(',')})`);
  const existing = await services.db({
    query: `SELECT website_url, phone, company_name FROM leads WHERE ${clauses.join(' OR ')}`,
    parameters: [],
    limit: 1000
  });
  if (existing.status !== 'completed') throw new Error(existing.error || 'Batch duplicate check failed');

  const cleanUrl = (u) => String(u || '').toLowerCase().replace(/\/$/, '');
  const cleanName = (n) => String(n || '').trim().toLowerCase();
  const existingUrls = new Set((existing.rows || []).map(r => cleanUrl(r.website_url)).filter(Boolean));
  const existingPhones = new Set((existing.rows || []).map(r => clean(r.phone)).filter(Boolean));
  const existingNames = new Set((existing.rows || []).map(r => cleanName(r.company_name)).filter(Boolean));
  const annotated = leads.map(l => {
    const exists = existingUrls.has(cleanUrl(l.url)) || (l.phone !== 'N/A' && existingPhones.has(l.phone)) || (l.company_name !== 'Unknown' && existingNames.has(cleanName(l.company_name)));
    return { ...l, duplicate_status: exists ? 'existing' : 'new' };
  });
  const total_skipped = annotated.filter(l => l.duplicate_status === 'existing').length;
  const total_new = annotated.length - total_skipped;
  const queued = annotated.slice()
    .sort((a, b) => (a.duplicate_status === 'new' ? 0 : 1) - (b.duplicate_status === 'new' ? 0 : 1))
    .slice(0, MAX_LEADS_PER_RUN);
  return { items: queued, total_found: annotated.length, total_new, total_skipped, total_queued: queued.length, max_leads_per_run: MAX_LEADS_PER_RUN };
};

module.exports = async function({ input }) {
  const rows = (input && input.rows) || [];
  const esc = (s)=>String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  const counts = {};
  for (const r of rows){ const s=(r.status||'new'); counts[s]=(counts[s]||0)+1; }
  const chip = (s)=>{ const c = s==='hot'?'#16a34a':(s==='warm'?'#d4af37':(s==='new'?'#2563eb':(s==='enrichment_failed'?'#b91c1c':'#6b7280')));
    return '<span style="background:'+c+';color:#fff;padding:2px 8px;border-radius:10px;font-size:11px;">'+esc(s||'new')+'</span>'; };
  let trs = rows.map(r=>'<tr>'
    +'<td style="padding:9px 10px;border-bottom:1px solid #eee;"><strong>'+esc(r.company_name)+'</strong><br/>'
    +'<a href="'+esc(r.website_url)+'" style="color:#9c7a1f;font-size:12px;">'+esc(r.website_url)+'</a><br/>'
    +'<span style="font-size:11px;color:#777;">'+esc(r.created_at||'')+'</span></td>'
    +'<td style="padding:9px 10px;border-bottom:1px solid #eee;font-size:13px;">'+esc(r.phone||'—')+'<br/>'+esc(r.email||'—')+'</td>'
    +'<td style="padding:9px 10px;border-bottom:1px solid #eee;">'+chip(r.status||'new')+'</td>'
    +'<td style="padding:9px 10px;border-bottom:1px solid #eee;font-size:12px;color:#444;">'+esc((r.notes||'').slice(0,220))+'</td>'
    +'</tr>').join('');
  if(!trs) trs='<tr><td colspan="4" style="padding:16px;color:#666;">Keine neuen Leads in diesem Lauf — alle gefundenen Firmen waren bereits in der Datenbank oder wurden durch ON CONFLICT übersprungen.</td></tr>';
  const summary = Object.keys(counts).map(k=>counts[k]+' '+k).join('  ·  ') || '0 neue Leads';
  const html = '<div style="font-family:Arial,Helvetica,sans-serif;background:#f7f5f0;padding:24px;">'
   +'<table width="100%" style="max-width:760px;margin:0 auto;background:#fff;border-radius:8px;overflow:hidden;border:1px solid #e8e1d0;">'
   +'<tr><td style="background:#0a0a0a;padding:22px 28px;"><span style="color:#d4af37;font-size:20px;font-weight:bold;letter-spacing:1px;">DEE EMPIRE</span>'
   +'<span style="color:#fff;font-size:12px;float:right;margin-top:6px;">DATA SCRAPING REPORT</span></td></tr>'
   +'<tr><td style="padding:24px 28px;"><h2 style="margin:0 0 6px;color:#0a0a0a;">'+rows.length+' neue Leads in diesem Lauf</h2>'
   +'<p style="margin:0 0 18px;color:#555;font-size:14px;">'+esc(summary)+'</p>'
   +'<table width="100%" style="border-collapse:collapse;font-size:13px;">'
   +'<tr style="background:#fbf7ec;"><th align="left" style="padding:8px 10px;color:#9c7a1f;">Unternehmen</th>'
   +'<th align="left" style="padding:8px 10px;color:#9c7a1f;">Kontakt</th>'
   +'<th align="left" style="padding:8px 10px;color:#9c7a1f;">Status</th>'
   +'<th align="left" style="padding:8px 10px;color:#9c7a1f;">Icebreaker / Notiz</th></tr>'+trs+'</table></td></tr>'
   +'<tr><td style="background:#0a0a0a;padding:16px 28px;text-align:center;">'
   +'<span style="color:#cfcfcf;font-size:11px;">Dee Empire — automatisierter Data-Scraping-Lauf</span></td></tr></table></div>';
  return { html, subject: 'Dee Empire Data Scraping: '+rows.length+' neue Leads gesammelt', count: rows.length };
};
